svg.script:
function MultistageWidgetFunc(e, cur_num_widgets) {
    let slide_nums = e.target.dataset.onclickcontainer_slides.split(",");
    let current_slide_index = slide_nums.indexOf(e.target.dataset.onclickcontainer_currentslide);
    let next_slide;
    if (current_slide_index == slide_nums.length-1)
        next_slide = 0;
    else 
        next_slide = parseInt(slide_nums[current_slide_index+1]);

    document.querySelectorAll(`#workspace .w${cur_num_widgets}.widget_parent[data-onclickele_group="${e.target.dataset.onclickcontainer_group}"]`).forEach(wi => {
        RecursiveSetOnClickChildrenVisibility(wi, cur_num_widgets, true, "#workspace", null);
    });
    document.querySelectorAll(`#workspace .w${cur_num_widgets}.widget_parent[data-onclickele_group="${e.target.dataset.onclickcontainer_group}"][data-onclickele_slide="${next_slide}"]`).forEach(wi => {
        RecursiveSetOnClickChildrenVisibility(wi, cur_num_widgets, false, "#workspace", null);
    });
    e.target.dataset.onclickcontainer_currentslide = next_slide;

    InvokeAutoCalc(e.target);
}function ForwardArrowWidgetFunc(e, cur_num_widgets) {
    let main_container = document.querySelector(`.w${cur_num_widgets}.onclickcontainer[data-onclickcontainer_group="${e.target.dataset.onclickcontainer_group}"]`);
    let slide_nums = main_container.dataset.onclickcontainer_slides.split(",");
    let current_slide_index = slide_nums.indexOf(main_container.dataset.onclickcontainer_currentslide);
    let next_slide;
    let next_slide_index;
    if (current_slide_index == slide_nums.length-1) {
        next_slide = slide_nums[0];
        next_slide_index = 0;
    } else {
        next_slide = parseInt(slide_nums[current_slide_index+1]);
        next_slide_index = current_slide_index+1;
    }

    main_container.dataset.onclickcontainer_currentslide = next_slide;
    document.querySelectorAll(`.w${cur_num_widgets}.widget_parent[data-onclickele_group="${main_container.dataset.onclickcontainer_group}"]`).forEach(wi => {
        RecursiveSetOnClickChildrenVisibility(wi, cur_num_widgets, true, "#workspace", null);
    });
    document.querySelectorAll(`.w${cur_num_widgets}.widget_parent[data-onclickele_group="${main_container.dataset.onclickcontainer_group}"][data-onclickele_slide="${next_slide}"]`).forEach(wi => {
        if (wi.dataset.onclickdeleteentry_group == e.target.dataset.onclickcontainer_group) {
            return;
        }

        RecursiveSetOnClickChildrenVisibility(wi, cur_num_widgets, false, "#workspace", null);
    });

    InvokeAutoCalc(main_container);
}function BackwardArrowWidgetFunc(e, cur_num_widgets) {
    let main_container = document.querySelector(`.w${cur_num_widgets}.onclickcontainer[data-onclickcontainer_group="${e.target.dataset.onclickcontainer_group}"]`);
    let slide_nums = main_container.dataset.onclickcontainer_slides.split(",");
    let current_slide_index = slide_nums.indexOf(main_container.dataset.onclickcontainer_currentslide);
    let next_slide;
    let next_slide_index;
    if (current_slide_index == 0) {
        next_slide = parseInt(slide_nums[slide_nums.length-1]);
        next_slide_index = slide_nums.length-1;
    } else {
        next_slide = parseInt(slide_nums[current_slide_index-1]);
        next_slide_index = current_slide_index-1;
    }
    main_container.dataset.onclickcontainer_currentslide = next_slide;
    document.querySelectorAll(`.w${cur_num_widgets}.widget_parent[data-onclickele_group="${main_container.dataset.onclickcontainer_group}"]`).forEach(wi => {
        RecursiveSetOnClickChildrenVisibility(wi, cur_num_widgets, true, "#workspace", null);
    });
    document.querySelectorAll(`.w${cur_num_widgets}.widget_parent[data-onclickele_group="${main_container.dataset.onclickcontainer_group}"][data-onclickele_slide="${next_slide}"]`).forEach(wi => {
        if (wi.dataset.onclickdeleteentry_group != '0' && next_slide_index == 0)
            return;

        RecursiveSetOnClickChildrenVisibility(wi, cur_num_widgets, false, "#workspace", null);
    });

    InvokeAutoCalc(main_container);
}function NewEntryWidgetFunc(e, cur_num_widgets) {
    let main_container = document.querySelector(`.w${cur_num_widgets}.onclickcontainer[data-onclickcontainer_group="${e.target.dataset.onclickcontainer_group}"]`);
    let first_children = document.querySelectorAll(`.w${cur_num_widgets}[data-onclickele_group="${e.target.dataset.onclickcontainer_group}"][data-onclickele_slide="0"]`);
    let slide_nums = main_container.dataset.onclickcontainer_slides.split(",");
    let slide_max = parseInt(slide_nums[slide_nums.length-1]) + 1;
    main_container.dataset.onclickcontainer_slides += `,${slide_max}`;
    let max = Math.max(...Array.from(document.querySelectorAll(`.w${cur_num_widgets}.onclickcontainer`)).map(x => parseInt(x.dataset.onclickcontainer_group)));
    RecursiveDuplicateOnClickChildren(Array.from(first_children), cur_num_widgets, max, slide_max);
}function DeleteEntryWidgetFunc(e, cur_num_widgets) {
    let cur_slide = e.explicitOriginalTarget.dataset.onclickele_slide;
    let main_container = document.querySelector(`.w${cur_num_widgets}.onclickcontainer[data-onclickcontainer_group="${e.explicitOriginalTarget.dataset.onclickele_group}"]`);
    let slide_eles = document.querySelectorAll(`.w${cur_num_widgets}[data-onclickele_group="${e.explicitOriginalTarget.dataset.onclickele_group}"][data-onclickele_slide="${cur_slide}"]`);
    RecursiveDeleteOnClickChildren(slide_eles, cur_num_widgets);
    let slide_nums = main_container.dataset.onclickcontainer_slides.split(",");
    let slide_index = slide_nums.indexOf(cur_slide);
    slide_nums.splice(slide_index, 1);
    main_container.dataset.onclickcontainer_slides = slide_nums.toString();
    main_container.dataset.onclickcontainer_currentslide = slide_nums[slide_index-1];
    document.querySelectorAll(`.w${cur_num_widgets}.widget_parent[data-onclickele_group="${main_container.dataset.onclickcontainer_group}"][data-onclickele_slide="${slide_nums[slide_index-1]}"]`).forEach(wi => {
        if (wi.dataset.onclickdeleteentry_group != '0' && slide_index-1 == 0)
            return;

        RecursiveSetOnClickChildrenVisibility(wi, cur_num_widgets, false, "", null);
    });

}function ExpandWidgetFunc(e, cur_num_widgets) {
    let main_container = document.querySelector(`.w${cur_num_widgets}.onclickexpand[data-onclickcontainer_group="${e.target.dataset.onclickcontainer_group}"]`);
    let main_hideable_container = document.querySelector(`.w${cur_num_widgets}.onclickexpandele[data-onclickcontainer_group="${e.target.dataset.onclickcontainer_group}"]`);
    let slide_nums = main_container.dataset.onclickcontainer_slides.split(",");
    let current_slide_index = slide_nums.indexOf(main_container.dataset.onclickcontainer_currentslide);
    let next_slide = current_slide_index == 1 ? 0 : 1;
    main_container.dataset.onclickcontainer_currentslide = next_slide;
    if (next_slide == 0) {
        document.querySelectorAll(`.w${cur_num_widgets}.widget_parent[data-onclickexpandele_group="${main_container.dataset.onclickcontainer_group}"]`).forEach(wi => {
            RecursiveSetOnClickChildrenVisibility(wi, cur_num_widgets, null, "", true);
        });
        document.querySelectorAll(`.w${cur_num_widgets}.widget_parent[data-onclickexpand_group="${main_container.dataset.onclickcontainer_group}"][data-onclickele_slide="1"]`).forEach(wi => {
            RecursiveSetOnClickChildrenVisibility(wi, cur_num_widgets, true, "", null);
        });
        document.querySelectorAll(`.w${cur_num_widgets}.widget_parent[data-onclickexpand_group="${main_container.dataset.onclickcontainer_group}"][data-onclickele_slide="0"]`).forEach(wi => {
            RecursiveSetOnClickChildrenVisibility(wi, cur_num_widgets, false, "", null);
        });
        let ignored_elements = Array.from(document.querySelectorAll(`.w${cur_num_widgets}.widget_parent[data-onclickexpandele_group="${main_container.dataset.onclickcontainer_group}"]`));
        ignored_elements.push(main_hideable_container);
        let top, left, bottom, right;
        Array.from(e.target.parentNode.children).forEach(c => {
            if (!ignored_elements.includes(c)) {
                let offset_x = NumberOrNull(parseFloat(c.dataset.x1)) ?? 0;
                let offset_y = NumberOrNull(parseFloat(c.dataset.y1)) ?? 0;
                if (!left || c.offsetLeft + offset_x < left)
                    left = c.offsetLeft + offset_x;
                if (!top || c.offsetTop + offset_y < top)
                    top = c.offsetTop + offset_y;
                if (!right || c.offsetLeft + offset_x + c.offsetWidth > right)
                    right = c.offsetLeft + offset_x + c.offsetWidth;
                if (!bottom || c.offsetTop + offset_y + c.offsetHeight > bottom)
                    bottom = c.offsetTop + offset_y + c.offsetHeight;
            }
        });
        e.target.parentNode.style.width = right - left + "px";
        e.target.parentNode.style.height = bottom - top + "px";
        //RefitWidgetHolder(GetWidgetContainer(main_container), ignored_elements);
    } else {
        document.querySelectorAll(`.w${cur_num_widgets}.widget_parent[data-onclickexpandele_group="${main_container.dataset.onclickcontainer_group}"]`).forEach(wi => {
            RecursiveSetOnClickChildrenVisibility(wi, cur_num_widgets, null, "", false);
        });
        document.querySelectorAll(`.w${cur_num_widgets}.widget_parent[data-onclickexpand_group="${main_container.dataset.onclickcontainer_group}"][data-onclickele_slide="0"]`).forEach(wi => {
            RecursiveSetOnClickChildrenVisibility(wi, cur_num_widgets, true, "", null);
        });
        document.querySelectorAll(`.w${cur_num_widgets}.widget_parent[data-onclickexpand_group="${main_container.dataset.onclickcontainer_group}"][data-onclickele_slide="1"]`).forEach(wi => {
            RecursiveSetOnClickChildrenVisibility(wi, cur_num_widgets, false, "", null);
        });
        let top, left, bottom, right;
        Array.from(e.target.parentNode.children).forEach(c => {
            let offset_x = NumberOrNull(parseFloat(c.dataset.x1)) ?? 0;
            let offset_y = NumberOrNull(parseFloat(c.dataset.y1)) ?? 0;
            if (!left || c.offsetLeft + offset_x < left)
                left = c.offsetLeft + offset_x;
            if (!top || c.offsetTop + offset_y < top)
                top = c.offsetTop + offset_y;
            if (!right || c.offsetLeft + offset_x + c.offsetWidth > right)
                right = c.offsetLeft + offset_x + c.offsetWidth;
            if (!bottom || c.offsetTop + offset_y + c.offsetHeight > bottom)
                bottom = c.offsetTop + offset_y + c.offsetHeight;
        });
        e.target.parentNode.style.width = right - left + "px";
        e.target.parentNode.style.height = bottom - top + "px";
        //RefitWidgetHolder(GetWidgetContainer(main_container));
    }

    InvokeAutoCalc(e.target);
}function SetUpOnClickForChildren(group, extra_class, cur_num_widgets, widget_funcs=null) {
    if (group && group != "0") {
        let func = function(e) {
            let parent = document.querySelector(`.w${cur_num_widgets}${extra_class ?? ":not(.onclickforwardarrow):not(.onclickbackwardarrow):not(.onclicknewentry):not(.onclickdeleteentry):not(.onclickexpand)"}[data-onclickcontainer_group="${group}"]:not(.onclick_notclick)`);
            if (parent)
                parent.click();
        }
        if (widget_funcs)
            widget_funcs.push(func);
        else
            return func;
    }
}function SetMultistageState(ele, cur_num_widgets, slide_num, first_class="", display_hide=false, popup=false) {
    let slide_nums = ele.dataset.onclickcontainer_slides.split(",");

    if (slide_nums.length <= slide_num && slide_num >= 0) {
        return;
    }

    let next_slide = parseInt(slide_nums[slide_num]);

    document.querySelectorAll(`${first_class} .w${cur_num_widgets}.widget_parent[data-onclickele_group="${ele.dataset.onclickcontainer_group}"]`).forEach(wi => {
        RecursiveSetOnClickChildrenVisibility(wi, cur_num_widgets, true, first_class, null, popup);
    });
    document.querySelectorAll(`${first_class} .w${cur_num_widgets}.widget_parent[data-onclickele_group="${ele.dataset.onclickcontainer_group}"][data-onclickele_slide="${next_slide}"]`).forEach(wi => {
        if (wi.dataset.onclickdeleteentry_group == ele.dataset.onclickcontainer_group) {
            return;
        }

        RecursiveSetOnClickChildrenVisibility(wi, cur_num_widgets, false, first_class, false, popup);
    });
    ele.dataset.onclickcontainer_currentslide = next_slide;
}function SetExpanderState(ele, cur_num_widgets, slide_num, first_class="") {
    if (slide_num != 0 && slide_num != 1)
        return;
    let main_container = document.querySelector(`.w${cur_num_widgets}.onclickexpand[data-onclickcontainer_group="${ele.dataset.onclickcontainer_group}"]`);
    let main_hideable_container = document.querySelector(`.w${cur_num_widgets}.onclickexpandele[data-onclickcontainer_group="${ele.dataset.onclickcontainer_group}"]`);
    let next_slide = slide_num;
    if (next_slide == 0) {
        document.querySelectorAll(`${first_class} .w${cur_num_widgets}.widget_parent[data-onclickexpandele_group="${main_container.dataset.onclickcontainer_group}"]`).forEach(wi => {
            RecursiveSetOnClickChildrenVisibility(wi, cur_num_widgets, null, first_class, true);
        });
        document.querySelectorAll(`${first_class} .w${cur_num_widgets}.widget_parent[data-onclickexpand_group="${main_container.dataset.onclickcontainer_group}"][data-onclickele_slide="1"]`).forEach(wi => {
            RecursiveSetOnClickChildrenVisibility(wi, cur_num_widgets, true, first_class, null);
        });
        document.querySelectorAll(`${first_class} .w${cur_num_widgets}.widget_parent[data-onclickexpand_group="${main_container.dataset.onclickcontainer_group}"][data-onclickele_slide="0"]`).forEach(wi => {
            RecursiveSetOnClickChildrenVisibility(wi, cur_num_widgets, false, first_class, null);
        });
        let ignored_elements = Array.from(document.querySelectorAll(`.w${cur_num_widgets}.widget_parent[data-onclickexpandele_group="${main_container.dataset.onclickcontainer_group}"]`));
        ignored_elements.push(main_hideable_container);
        let top, left, bottom, right;
        Array.from(ele.parentNode.children).forEach(c => {
            if (!ignored_elements.includes(c)) {
                let offset_x = NumberOrNull(parseFloat(c.dataset.x1)) ?? 0;
                let offset_y = NumberOrNull(parseFloat(c.dataset.y1)) ?? 0;
                if (!left || c.offsetLeft + offset_x < left)
                    left = c.offsetLeft + offset_x;
                if (!top || c.offsetTop + offset_y < top)
                    top = c.offsetTop + offset_y;
                if (!right || c.offsetLeft + offset_x + c.offsetWidth > right)
                    right = c.offsetLeft + offset_x + c.offsetWidth;
                if (!bottom || c.offsetTop + offset_y + c.offsetHeight > bottom)
                    bottom = c.offsetTop + offset_y + c.offsetHeight;
            }
        });
        ele.parentNode.style.width = right - left + "px";
        ele.parentNode.style.height = bottom - top + "px";
    } else {
        document.querySelectorAll(`${first_class} .w${cur_num_widgets}.widget_parent[data-onclickexpandele_group="${main_container.dataset.onclickcontainer_group}"]`).forEach(wi => {
            RecursiveSetOnClickChildrenVisibility(wi, cur_num_widgets, null, first_class, false);
        });
        document.querySelectorAll(`${first_class} .w${cur_num_widgets}.widget_parent[data-onclickexpand_group="${main_container.dataset.onclickcontainer_group}"][data-onclickele_slide="0"]`).forEach(wi => {
            RecursiveSetOnClickChildrenVisibility(wi, cur_num_widgets, true, first_class, null);
        });
        document.querySelectorAll(`${first_class} .w${cur_num_widgets}.widget_parent[data-onclickexpand_group="${main_container.dataset.onclickcontainer_group}"][data-onclickele_slide="1"]`).forEach(wi => {
            RecursiveSetOnClickChildrenVisibility(wi, cur_num_widgets, false, first_class, null);
        });
        let top, left, bottom, right;
        Array.from(ele.parentNode.children).forEach(c => {
            let offset_x = NumberOrNull(parseFloat(c.dataset.x1)) ?? 0;
            let offset_y = NumberOrNull(parseFloat(c.dataset.y1)) ?? 0;
            if (!left || c.offsetLeft + offset_x < left)
                left = c.offsetLeft + offset_x;
            if (!top || c.offsetTop + offset_y < top)
                top = c.offsetTop + offset_y;
            if (!right || c.offsetLeft + offset_x + c.offsetWidth > right)
                right = c.offsetLeft + offset_x + c.offsetWidth;
            if (!bottom || c.offsetTop + offset_y + c.offsetHeight > bottom)
                bottom = c.offsetTop + offset_y + c.offsetHeight;
        });
        ele.parentNode.style.width = right - left + "px";
        ele.parentNode.style.height = bottom - top + "px";
    }

    main_container.dataset.onclickcontainer_currentslide = next_slide;
}function InvokeAutoCalc(ele, updated_chain=[]) {
    if (ele.dataset.local_tag_name) {
        let change_event = new CustomEvent("update_automatic_calculations", { detail: { updated_ele: ele, updated_chain: updated_chain } });
        Array.from(document.querySelectorAll(`#workspace .w${GetCurNumWidgetsFromWidget(ele)}`)).forEach(x => {
            if (x.dataset.automatic_calculation && x.dataset.automatic_calculation.split(",").includes(ele.dataset.local_tag_name))
                x.dispatchEvent(change_event);
        });
    }
    if (ele.dataset.tag_name) {
        let change_event = new CustomEvent("update_automatic_calculations", { detail: { updated_ele: ele, updated_chain: updated_chain } });
        Array.from(document.querySelectorAll("#workspace .widget")).forEach(x => {
            if (x.dataset.automatic_calculation && x.dataset.automatic_calculation.split(",").includes(ele.dataset.tag_name))
                x.dispatchEvent(change_event);
        });
    }
}function AutoCalcEvent(ele, cur_num_widgets) {
    ele.addEventListener("update_automatic_calculations", (e) => {
        if (e.detail.updated_chain.includes(ele))
            return;

        let tokens = SafariProofSplit(ele.dataset.automatic_calculation);
        let new_value;
        try {
            new_value = AutoCalcParser(tokens, cur_num_widgets, e.detail.updated_ele);
        } catch (err) {
            console.log(err)
            return;
        }

        if (ele.classList.contains("onclickexpand")) {
            if (!isNaN(parseInt(new_value)) && parseInt(new_value) > 0) {
                let slide_index = parseInt(new_value)-1;
                let slides = ele.dataset.onclickcontainer_slides.split(",");
                if (slides.length > slide_index) {
                    SetExpanderState(ele, cur_num_widgets, slide_index);
                }
            }
        } else if (ele.classList.contains("onclickcontainer")) {
            if (!isNaN(parseInt(new_value)) && parseInt(new_value) > 0) {
                let slide_index = parseInt(new_value)-1;
                let slides = ele.dataset.onclickcontainer_slides.split(",");
                if (slides.length > slide_index) {
                    SetMultistageState(ele, cur_num_widgets, slide_index);
                }
            }
        } else if (ele.tagName.toLowerCase() === 'input' && ele.type.toLowerCase() == "checkbox") {
            ele.checked = new_value;
        } else if (ele.tagName.toLowerCase() === 'input' || ele.tagName.toLowerCase() === 'textarea') {
            ele.value = new_value;
        } else if (ele.tagName.toLowerCase() === 'select') {
            mm_get(ele).getChildren("option").forEach(x => {
                if (x.getElement().value == new_value) 
                    x.selected(true);
            });
        } else {
            ele.innerHTML = DOMPurify.sanitize(new_value.toString().split("\n").map(x => { if (ValueOrNull(x)) return `<div>${x}</div>`; else return "<div><br></div>" }).join(""));
        }

        InvokeAutoCalc(ele, [...e.detail.updated_chain, ele]);
    });
}function AutoCalcParser(all_tokens, cur_num_widgets, updated_ele=null, error_checking=false) {
    let get_first_index_of_set = (tokens, set) => {
        let min_index = null;
        for (let i = 0; i < set.length; i++) {
            let new_index = tokens.map(x => x.type).indexOf(set[i]);
            if (new_index != -1 && (!min_index || new_index < min_index))
                min_index = new_index;
        }
        return min_index;
    };

    let valid_selector = (selector) => {
        let ele = null;
        try {
            ele = document.querySelector(selector);
        } catch {
            return false;
        }
        return ele;
    };

    if (!all_tokens.length)
        return;

    for (let i = 0; i < all_tokens.length; i++) {
        if (TAG_INFO.filter(v => v.name == all_tokens[i]).length) {
            let name = TAG_INFO.filter(v => v.name == all_tokens[i])[0].name;
            if (name == "true" || name == "false")
                all_tokens[i] = { type: "bool", value: name == "true" };
            else
                all_tokens[i] = { type: TAG_INFO.filter(v => v.name == all_tokens[i])[0].name, value: "" };
        } else if (all_tokens[i].match(/^[\-+]?[0-9]*\.?[0-9]+$/)) {
            all_tokens[i] = { type: "number", value: parseFloat(all_tokens[i]) };
        } else if (!TAG_INFO.filter(v => v.name == all_tokens[i]).length && (valid_selector(`#workspace .widget[data-tag_name='${all_tokens[i]}']`) || valid_selector(`#workspace .w${cur_num_widgets}[data-local_tag_name='${all_tokens[i]}']`))) {
            let ele;
            if (all_tokens[i].substring(0, 1) == ".") {
                ele = document.querySelector(`${error_checking ? "" : "#workspace"} .w${cur_num_widgets}[data-local_tag_name='${all_tokens[i]}']`);
            } else {
                ele = document.querySelector(`${error_checking ? "" : "#workspace"} .widget[data-tag_name='${all_tokens[i]}']`);
            }

            if (ele.tagName.toLowerCase() == "input" && ele.type.toLowerCase() == "checkbox") {
                all_tokens[i] = { type: "bool", value: ele.checked, updated: updated_ele == ele };
            } else if (ele.classList.contains("onclickcontainer") || ele.classList.contains("onclickexpander")) {
                all_tokens[i] = { type: "number", value: ele.dataset.onclickcontainer_slides.split(",").indexOf(ele.dataset.onclickcontainer_currentslide)+1, updated: updated_ele == ele };
            } else if (ele.value?.length && ele.value.match(/^[\-+]?[0-9]*\.?[0-9]+$/)) {
                if (ele.tagName.toLowerCase() == "div")
                    all_tokens[i] = { type: "number", value: parseFloat(ele.innerText), updated: updated_ele == ele };
                else
                    all_tokens[i] = { type: "number", value: parseFloat(ele.value), updated: updated_ele == ele };
            } else {
                if (ele.tagName.toLowerCase() == "div")
                    all_tokens[i] = { type: "string", value: ele.innerText, updated: updated_ele == ele };
                else
                    all_tokens[i] = { type: "string", value: ele.value, updated: updated_ele == ele };
            }
        } else if (all_tokens[i].substring(0, 1) == "\"") {
            all_tokens[i] = { type: "string", value: all_tokens[i].substring(1, all_tokens[i].length).replaceAll("\\,", ",").replaceAll("\\\\", "\\") };
        } else {
            console.log("error", all_tokens[i]);
            throw new Error(`Unknown error.`);
        }
    }

    let auto_calc = (tokens) => {
        let token_types = [["*", "/", "//", "%", "random"], ["+", "-", "round"], ["not", "updated"], ["==", "!=", "<", ">", "<=", ">="], ["and", "or"]];
        for (let i = 0; i < tokens.length; i++) {
            let index = get_first_index_of_set(tokens, token_types[0]);

            if (index == null)
                break;

            if (index == 0)
                throw new Error(`Must have another tag before ${tokens[index].type} operator.`);

            if (tokens.length <= index+1)
                throw new Error(`Must have another tag after ${tokens[index].type} operator.`);

            let f1 = tokens[index-1];
            let f2 = tokens[index+1];

            if (f1.type != "number" || f2.type != "number")
                throw new Error(`Must have a number/widget tag after ${tokens[index].type} operator.`);

            let new_node = {
                type: "number",
            };
            if (tokens[index].type == "*") {
                new_node.value = f1.value * f2.value;
            } else if (tokens[index].type == "/") {
                new_node.value = f1.value / f2.value;
            } else if (tokens[index].type == "%") {
                new_node.value = f1.value % f2.value;
            } else if (tokens[index].type == "//") {
                new_node.value = Math.floor(f1.value / f2.value);
            } else if (tokens[index].type == "random") {
                new_node.value = f1.value + Math.floor(Math.random() * (f2.value - f1.value + 1));
            }
            tokens[index-1] = new_node;
            tokens.splice(index, 2);
        }
        for (let i = 0; i < tokens.length; i++) {
            let index = get_first_index_of_set(tokens, token_types[1]);

            if (index == null)
                break;

            if (index == 0)
                throw new Error(`Must have another tag before ${tokens[index].type} operator.`);

            if (tokens.length <= index+1)
                throw new Error(`Must have another tag after ${tokens[index].type} operator.`);

            let f1 = tokens[index-1];
            let f2 = tokens[index+1];
            let new_node = {
                type: "",
            };
            if (tokens[index].type == "+") {
                new_node.value = f1.value + f2.value;
                if (f1.type == "string" || f2.type == "string")
                    new_node.type = "string";
                else if (f1.type == "number" && f2.type == "number")
                    new_node.type = "number";
                else 
                    throw new Error(`Must have a number/text/widget tag before and after ${tokens[index].type} operator.`)
            } else if (tokens[index].type == "-") {
                if (f1.type != "number" || f2.type != "number")
                    throw new Error(`Must have a number/widget tag before and after ${tokens[index].type} operator.`);
                new_node.value = f1.value - f2.value;
                new_node.type = "number";
            } else if (tokens[index].type == "round") {
                if (f1.type != "number" || f2.type != "number")
                    throw new Error(`Must have a number/widget tag before and after ${tokens[index].type} operator.`);
                if (f2.value < 0) {
                    let step = Math.pow(10, Math.round(f2.value) * -1);
                    new_node.value = Math.round(f1.value / step) * step;
                    new_node.type = "number";
                } else {
                    new_node.value = f1.value.toFixed(f2.value);
                    new_node.type = "number";
                }
            }
            tokens[index-1] = new_node;
            tokens.splice(index, 2);
        }
        for (let i = 0; i < tokens.length; i++) {
            let index = get_first_index_of_set(tokens, token_types[2]);

            if (index == null)
                break;

            if (tokens.length <= index+1)
                throw new Error(`Must have another tag after ${tokens[index].type} operator.`);

            let f1 = tokens[index+1];

            let new_node = {
                type: "bool",
                value: !f1.value
            };

            if (tokens[index].type == "not") {
                if (f1.type != "bool")
                    throw new Error(`The tag after ${tokens[index].type} operator must result in a True/False value.`);

                new_node.value = !f1.value;
            } else if (tokens[index].type == "updated") {
                new_node.value = f1.updated == true;
            }

            tokens[index] = new_node;
            tokens.splice(index+1, 1);
        }
        for (let i = 0; i < tokens.length; i++) {
            let index = get_first_index_of_set(tokens, token_types[3]);

            if (index == null)
                break;

            if (index == 0)
                throw new Error(`Must have another tag before ${tokens[index].type} operator.`);

            if (tokens.length <= index+1)
                throw new Error(`Must have another tag after ${tokens[index].type} operator.`);

            let f1 = tokens[index-1];
            let f2 = tokens[index+1];

            if (!["number", "string", "bool"].includes(f1.type) || !["number", "string", "bool"].includes(f2.type))
                throw new Error(`Tags before and after ${tokens[index].type} operator must be Number, Text, or widget tags.`);

            let new_node = {
                type: "bool",
            };
            if (tokens[index].type == "==") {
                new_node.value = f1.value == f2.value;
            } else if (tokens[index].type == "!=") {
                new_node.value = f1.value != f2.value;
            } else if (tokens[index].type == ">") {
                new_node.value = f1.value > f2.value;
            } else if (tokens[index].type == "<") {
                new_node.value = f1.value < f2.value;
            } else if (tokens[index].type == ">=") {
                new_node.value = f1.value >= f2.value;
            } else if (tokens[index].type == "<=") {
                new_node.value = f1.value <= f2.value;
            }
            tokens[index-1] = new_node;
            tokens.splice(index, 2);
        }
        for (let i = 0; i < tokens.length; i++) {
            let index = get_first_index_of_set(tokens, token_types[4]);

            if (index == null)
                break;

            if (index == 0)
                throw new Error(`Must have another tag before ${tokens[index].type} operator.`);

            if (tokens.length <= index+1)
                throw new Error(`Must have another tag after ${tokens[index].type} operator.`);

            let f1 = tokens[index-1];
            let f2 = tokens[index+1];

            if (f1.type != "bool" || f2.type != "bool")
                throw new Error(`Tags before and after ${tokens[index].type} operator must result in a True/False value.`);

            let new_node = {
                type: "bool",
            };
            if (tokens[index].type == "and") {
                new_node.value = f1.value && f2.value;
            } else if (tokens[index].type == "or") {
                new_node.value = f1.value || f2.value;
            }
            tokens[index-1] = new_node;
            tokens.splice(index, 2);
        }

        let if_index = tokens.map(x => x.type).indexOf("if");
        while (true) {
            if (tokens.length == 1 && ["number", "string", "bool"].includes(tokens[0].type)) {
                return tokens[0];
            }

            if (if_index == -1) {
                throw new Error("Incorrect if statement syntax.");
            }

            if (tokens.length <= if_index+3)
                throw new Error("Incorrect if statement syntax.");

            if (tokens[if_index+2].type == "then" && tokens[if_index+3].type != "if" && (tokens.length == if_index+4 || (tokens.length > if_index+5 && tokens[if_index+4].type == "else" && tokens[if_index+5].type != "if"))) {
                let result;

                if (tokens[if_index+1].type != "bool")
                    throw new Error("If condition must result in a true/false value.");

                if (tokens[if_index+1].value) {
                    result = tokens[if_index+3];
                } else if (tokens.length > if_index+5 && tokens[if_index+4].type == "else") {
                    result = tokens[if_index+5];
                } else {
                    result = { type: "string", value: "" };
                }
                tokens[if_index] = {
                    type: result.type,
                    value: result.value
                };
                if (tokens.length > if_index+5 && tokens[if_index+4].type == "else")
                    tokens.splice(if_index+1, 5);
                else 
                    tokens.splice(if_index+1, 3);
                if_index = tokens.map(x => x.type).indexOf("if");
            } else {
                if_index = tokens.map(x => x.type).indexOf("if", if_index+1);
            }
        }
    };

    let op_index = null;
    let i = 0;
    while (true) {
        if (i >= all_tokens.length)
            break;

        if (all_tokens[i].type == "(") {
            op_index = i;
        }
        else if (all_tokens[i].type == ")") {
            if (op_index == null)
                throw new Error("Unexpected ).");

            let result = auto_calc(all_tokens.slice(op_index+1, i));
            all_tokens[op_index] = result;
            all_tokens.splice(op_index+1, i - op_index);
            op_index = null;
            i = 0;
            continue;
        }

        if (i == all_tokens.length-1 && op_index != null) {
            throw new Error("Expected ).");
        }

        i++;
    }

    return auto_calc(all_tokens).value;
}function SafariProofSplit(str) {
    if (str == "")
        return "";
    return str.split("").reverse().join("").split(/,(?!\\)/).reverse().map(x => x.split("").reverse().join(""));
}function GetOnClickWidgetChildren(target, cur_num_widgets=null, first_class="") {
    if (cur_num_widgets==null)
        cur_num_widgets = total_widgets;

    let ws = [];
    if (target.classList.contains("onclickcontainer"))
        Array.from(document.querySelectorAll(`${first_class} .w${cur_num_widgets}.widget_parent[data-onclickele_group='${target.dataset.onclickcontainer_group}']`)).forEach(w => {
            if (w != target)
                ws.push(w);
        });
    if (target.classList.contains("onclickforwardarrow"))
        Array.from(document.querySelectorAll(`${first_class} .w${cur_num_widgets}.widget_parent[data-onclickforwardarrow_group='${target.dataset.onclickcontainer_group}']`)).forEach(w => {
            if (w != target)
                ws.push(w);
        });
    if (target.classList.contains("onclickbackwardarrow"))
        Array.from(document.querySelectorAll(`${first_class} .w${cur_num_widgets}.widget_parent[data-onclickbackwardarrow_group='${target.dataset.onclickcontainer_group}']`)).forEach(w => {
            if (w != target)
                ws.push(w);
        });
    if (target.classList.contains("onclicknewentry"))
        Array.from(document.querySelectorAll(`${first_class} .w${cur_num_widgets}.widget_parent[data-onclicknewentry_group='${target.dataset.onclickcontainer_group}']`)).forEach(w => {
            if (w != target)
                ws.push(w);
        });
    if (target.classList.contains("onclickdeleteentry"))
        Array.from(document.querySelectorAll(`${first_class} .w${cur_num_widgets}.widget_parent[data-onclickdeleteentry_group='${target.dataset.onclickcontainer_group}'][data-onclickele_slide='${target.dataset.onclickele_slide}']`)).forEach(w => {
            if (w != target)
                ws.push(w);
        });
    if (target.classList.contains("onclickexpandele"))
        Array.from(document.querySelectorAll(`${first_class} .w${cur_num_widgets}.widget_parent[data-onclickexpandele_group='${target.dataset.onclickcontainer_group}']`)).forEach(w => {
            if (w != target)
                ws.push(w);
        });
    return ws;
}function RecursiveSetOnClickChildrenVisibility(widget, cur_num_widgets, visibility_hide, first_class="", display_hide=true, popup=false) {
    if (!widget.classList.contains("widget"))
        return;
    if (visibility_hide != null) {
        widget.style.visibility = visibility_hide ? "hidden" : "";
        Array.from(widget.children).forEach(c => {
            if (c.classList.contains("widget"))
                c.style.visibility = visibility_hide ? "hidden" : "";
        });
    }
    if (display_hide != null) {
        widget.style.display = display_hide ? "none" : "flex";
        Array.from(widget.children).forEach(c => {
            if (c.classList.contains("widget"))
                c.style.display = display_hide ? "none" : "flex";
        });
    }
    if (!popup && widget.classList.contains("onclickdeleteentry") && widget.dataset.onclickele_slide == '0')
        widget.style.display = "none";

    let contained_widgets = GetOnClickWidgetChildren(widget, cur_num_widgets, first_class);

    if (!contained_widgets.length)
        return;

    if (widget.classList.contains("onclickforwardarrow") ||
    widget.classList.contains("onclickbackwardarrow") ||
    widget.classList.contains("onclicknewentry")) {
        contained_widgets.forEach(c => {
            RecursiveSetOnClickChildrenVisibility(c, cur_num_widgets, visibility_hide != true ? false : true, first_class, display_hide, popup);
        });
    } else if (widget.classList.contains("onclickdeleteentry")) {
        let container_ele = document.querySelector(`${first_class} .w${cur_num_widgets}.onclickcontainer[data-onclickcontainer_group='${widget.dataset.onclickcontainer_group}']`);
        contained_widgets.forEach(c => {
            if (container_ele && c.dataset.onclickele_slide == container_ele.dataset.onclickcontainer_currentslide &&
            (visibility_hide || display_hide || c.dataset.onclickdeleteentry_group == '0' || 
            c.dataset.onclickele_slide != '0' || popup))
                RecursiveSetOnClickChildrenVisibility(c, cur_num_widgets, visibility_hide != true ? false : true, first_class, display_hide != true ? false : true, popup);

        });
    } else if (widget.classList.contains("onclickexpand")) {
        contained_widgets.forEach(c => {
            if (visibility_hide || display_hide || 
            c.dataset.onclickele_slide == widget.dataset.onclickcontainer_currentslide)
                RecursiveSetOnClickChildrenVisibility(c, cur_num_widgets, visibility_hide != true ? false : true, first_class, display_hide, popup);
            else
                RecursiveSetOnClickChildrenVisibility(c, cur_num_widgets, true, first_class, display_hide, popup);
        });
    } else if (widget.classList.contains("onclickexpandele")) {
        let expand_ele = document.querySelector(`${first_class} .w${cur_num_widgets}.onclickexpand[data-onclickcontainer_group='${widget.dataset.onclickcontainer_group}']`);
        contained_widgets.forEach(c => {
            if (popup || visibility_hide || display_hide || 
            expand_ele.dataset.onclickcontainer_currentslide == "1" &&
            (c.dataset.onclickdeleteentry_group == '0' || c.dataset.onclickele_slide != '0'))
                RecursiveSetOnClickChildrenVisibility(c, cur_num_widgets, visibility_hide, first_class, display_hide != true ? false : true, popup);
            else
                RecursiveSetOnClickChildrenVisibility(c, cur_num_widgets, visibility_hide, first_class, true, popup);
        });
    } else if (widget.classList.contains("onclickcontainer")) {
        contained_widgets.forEach(c => {
            if (visibility_hide || display_hide || 
            c.dataset.onclickele_slide == widget.dataset.onclickcontainer_currentslide &&
            ((!c.classList.contains("onclickdeleteentry") && c.dataset.onclickdeleteentry_group == '0') || 
            c.dataset.onclickele_slide != '0' || popup))
                RecursiveSetOnClickChildrenVisibility(c, cur_num_widgets, visibility_hide != true ? false : true, first_class, display_hide, popup);
            else
                RecursiveSetOnClickChildrenVisibility(c, cur_num_widgets, true, first_class, display_hide, popup);
        });
    }
}function RecursiveDuplicateOnClickChildren(widgets, cur_num_widgets, max=null, new_slide_num=null) {
    widgets.forEach(c => {
        let new_child = c.cloneNode(true);
        new_child.onclick = c.onclick;
        new_child.onchange = c.onchange;
        new_child.style.visibility = "hidden";
        new_child.style.display = "block";
        if (new_slide_num)
            new_child.dataset.onclickele_slide = new_slide_num;
        else {
            Object.entries(oc_to_class).forEach(([k, v]) => {
                if (new_child.dataset[`${v}_group`] && new_child.dataset[`${v}_group`] != "0") {
                    new_child.dataset[`${v}_group`] = parseInt(new_child.dataset[`${v}_group`]) + max;
                }
            });
            let widget_funcs = [];
            SetUpOnClickForChildren(new_child.dataset.onclickele_group, null, cur_num_widgets, widget_funcs);
            SetUpOnClickForChildren(new_child.dataset.onclickforwardarrow_group, ".onclickforwardarrow", cur_num_widgets, widget_funcs);
            SetUpOnClickForChildren(new_child.dataset.onclickbackwardarrow_group, ".onclickbackwardarrow", cur_num_widgets, widget_funcs);
            SetUpOnClickForChildren(new_child.dataset.onclicknewentry_group, ".onclicknewentry", cur_num_widgets, widget_funcs);
            SetUpOnClickForChildren(new_child.dataset.onclickdeleteentry_group, ".onclickdeleteentry", cur_num_widgets, widget_funcs);
            SetUpOnClickForChildren(new_child.dataset.onclickexpand_group, ".onclickexpand", cur_num_widgets, widget_funcs);
            if (new_child.classList.contains("onclickcontainer") && !new_child.classList.contains("onclick_notclick") && !new_child.classList.contains("onclickexpand")) {
                widget_funcs.push((e) => MultistageWidgetFunc(e, cur_num_widgets));
            }
            if (new_child.classList.contains("onclickforwardarrow")) {
                widget_funcs.push((e) => ForwardArrowWidgetFunc(e, cur_num_widgets));
            }
            if (new_child.classList.contains("onclickbackwardarrow")) {
                widget_funcs.push((e) => BackwardArrowWidgetFunc(e, cur_num_widgets));
            }
            /*if (new_child.classList.contains("onclicknewentry")) {
                widget_funcs.push((e) => NewEntryWidgetFunc(e, cur_num_widgets));
            }
            if (new_child.classList.contains("onclickdeleteentry")) {
                widget_funcs.push((e) => DeleteEntryWidgetFunc(e, cur_num_widgets));
            }*/
            if (new_child.classList.contains("onclickexpand")) {
                widget_funcs.push((e) => ExpandWidgetFunc(e, cur_num_widgets));
            }
            new_child.onclick = (e) => { widget_funcs.forEach(f => f(e)) };
        }



        document.querySelector(`.w${cur_num_widgets}`).appendChild(new_child);

        if (new_child.classList.contains("onclickcontainer") || new_child.classList.contains("onclickforwardarrow") || 
        new_child.classList.contains("onclickbackwardarrow") || 
        //new_child.classList.contains("onclicknewentry") || 
        //new_child.classList.contains("onclickdeleteentry") || 
        new_child.classList.contains("onclickexpandele")) {
            RecursiveDuplicateOnClickChildren(GetOnClickWidgetChildren(new_child, cur_num_widgets), cur_num_widgets, max);
            new_child.dataset.onclickcontainer_group = parseInt(new_child.dataset.onclickcontainer_group) + max;
        }
    });
}function RecursiveDeleteOnClickChildren(widgets, cur_num_widgets) {
    widgets.forEach(c => {
        if (c.classList.contains("onclickcontainer") || 
        c.classList.contains("onclickforwardarrow") || 
        c.classList.contains("onclickbackwardarrow") || 
        //c.classList.contains("onclicknewentry") || 
        //c.classList.contains("onclickdeleteentry") || 
        c.classList.contains("onclickexpandele")) {
            RecursiveDeleteOnClickChildren(GetOnClickWidgetChildren(c, cur_num_widgets), cur_num_widgets);
        }

        c.remove();
    });
}function mm_parseFloat(value) {
    return parseFloat(value.replace(/[^0-9.-]/g, ''));
}var TAG_INFO = [{"name":"if","color":"var(--pink-tag)","title":"If"},{"name":"then","color":"var(--pink-tag)","title":"Then"},{"name":"else","color":"var(--pink-tag)","title":"Else"},{"name":"==","color":"var(--orange-tag)","title":"Equals"},{"name":"!=","color":"var(--orange-tag)","title":"Does Not Equal"},{"name":"<","color":"var(--orange-tag)","title":"Less Than"},{"name":">","color":"var(--orange-tag)","title":"Greater Than"},{"name":"<=","color":"var(--orange-tag)","title":"Less Than or Equal to"},{"name":">=","color":"var(--orange-tag)","title":"Greater Than or Equal to"},{"name":"and","color":"var(--orange-tag)","title":"And"},{"name":"or","color":"var(--orange-tag)","title":"Or"},{"name":"not","color":"var(--orange-tag)","title":"Not"},{"name":"updated","color":"var(--orange-tag)","title":"Updated"},{"name":"+","color":"var(--blue-tag)","title":"Addition","style":{"marginTop":"1px"}},{"name":"-","color":"var(--blue-tag)","title":"Subtraction","style":{"marginBottom":"2px"}},{"name":"*","color":"var(--blue-tag)","title":"Multiplication","style":{"marginTop":"7px"}},{"name":"/","color":"var(--blue-tag)","title":"Division"},{"name":"//","color":"var(--blue-tag)","title":"Integer Division"},{"name":"%","color":"var(--blue-tag)","title":"Remainder"},{"name":"(","color":"var(--blue-tag)","title":"Start Group","style":{"marginBottom":"2px"}},{"name":")","color":"var(--blue-tag)","title":"End Group","style":{"marginBottom":"2px"}},{"name":"random","color":"var(--blue-tag)","title":"Generate a Random Number ___ to ___"},{"name":"round","color":"var(--blue-tag)","title":"Round a number to a given specificity"},{"name":"Number","color":"var(--grey-tag)","title":"Numeric Value"},{"name":"Text","color":"var(--grey-tag)","title":"Text Value"},{"name":"true","color":"var(--grey-tag)","title":"True"},{"name":"false","color":"var(--grey-tag)","title":"False"}];var oc_to_class = {"onclickcontainer":"onclickele","onclickforwardarrow":"onclickforwardarrow","onclickbackwardarrow":"onclickbackwardarrow","onclicknewentry":"onclicknewentry","onclickdeleteentry":"onclickdeleteentry","onclickexpand":"onclickexpand","onclickexpandele":"onclickexpandele"};function ReAddJS() {
