                && !w.classList.contains("onclickbackwardarrow") 
                && !w.classList.contains("onclicknewentry") 
                && !w.classList.contains("onclickdeleteentry")
                && !w.classList.contains("onclickexpand")) {
                    let multistage_func = SetUpOnClickForChildren(w.dataset.onclickele_group, null, cur_num_widgets);
                    if (multistage_func)
                        multistage_func(e);
