                    if (forward_arrow_func)
                        forward_arrow_func(e);
                    let backward_arrow_func = SetUpOnClickForChildren(w.dataset.onclickbackwardarrow_group, ".onclickbackwardarrow", cur_num_widgets);
                    if (backward_arrow_func)
                        backward_arrow_func(e);
                    let new_entry_func = SetUpOnClickForChildren(w.dataset.onclicknewentry_group, ".onclicknewentry", cur_num_widgets);
                    if (new_entry_func)
                        new_entry_func(e);
                    let delete_entry_func = SetUpOnClickForChildren(w.dataset.onclickdeleteentry_group, ".onclickdeleteentry", cur_num_widgets);
                    if (delete_entry_func)
                        delete_entry_func(e);
                    let expand_func = SetUpOnClickForChildren(w.dataset.onclickexpand_group, ".onclickexpand", cur_num_widgets);
                    if (expand_func)
                        expand_func(e);
                }
                if (w.classList.contains("onclickcontainer") && !w.classList.contains("onclick_notclick") && !w.classList.contains("onclickexpand")) {
                    MultistageWidgetFunc(e, cur_num_widgets);
                }
                if (w.classList.contains("onclickforwardarrow")) {
                    ForwardArrowWidgetFunc(e, cur_num_widgets);
                }
                if (w.classList.contains("onclickbackwardarrow")) {
                    BackwardArrowWidgetFunc(e, cur_num_widgets);
                }
                if (w.classList.contains("onclicknewentry")) {
                    NewEntryWidgetFunc(e, cur_num_widgets);
                }
                if (w.classList.contains("onclickdeleteentry")) {
                    DeleteEntryWidgetFunc(e, cur_num_widgets);
                }
                if (w.classList.contains("onclickexpand")) {
                    ExpandWidgetFunc(e, cur_num_widgets);
                }
            };
            w.onchange = () => {
                InvokeAutoCalc(w);
            };
            if (w.dataset.automatic_calculation) {
                AutoCalcEvent(w, cur_num_widgets);
            }
        });
    }ReAddJS();
